+    loading,
+    error,
+    saving,
+    listDashboards,
+    getDashboard,
+    createDashboard,
+    updateDashboard,
+    deleteDashboard,
+    duplicateDashboard,
+    addWidget,
+    updateWidget,
+    removeWidget,
+    updateLayout,
+    fetchWidgetData,
+    toggleFavorite,
+    clearError,
+  } = useDashboard(dashboardId);
+
+  // Load dashboards list on mount
+  useEffect(() => {
+    listDashboards();
+  }, [listDashboards]);
+
+  // Handle creating a new dashboard
+  const handleCreate = async () => {
+    if (!newDashboardName.trim()) return;
+
+    const dashboard = await createDashboard({
+      name: newDashboardName.trim(),
+      description: "",
+    });
+
+    if (dashboard) {
+      setNewDashboardName("");
+      setShowCreateModal(false);
+      navigate({ to: `/dashboards/${dashboard.id}` });
